const t={macroDesigner:{intro:{t:0,b:{t:2,i:[{t:3}],s:"حاكِ G-code دون اتصال — الصق أو اكتب برنامجًا وشاهد مسار رأس الأداة، والمربّع المحيط، وإجماليات التنقّل والبثق، وتقديرًا للوقت، دون لمس الطابعة. تصفّح مكتبة الماكرو المدمجة كمرجع."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"مساعدة"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"حول مصمّم الماكرو"}},close:{t:0,b:{t:2,i:[{t:3}],s:"إغلاق"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"طريقة الاستخدام"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"اكتب أو الصق G-code في المحرّر (يُحمَّل مربّع نموذجي للبدء)."}},{t:0,b:{t:2,i:[{t:3}],s:"اضغط محاكاة — يتحدّث المسار ثنائي الأبعاد والإحصاءات."}},{t:0,b:{t:2,i:[{t:3}],s:"الخطوط المتّصلة هي حركات البثق؛ والخطوط المتقطّعة الباهتة هي حركات التنقّل."}},{t:0,b:{t:2,i:[{t:3}],s:"تصفّح مكتبة الماكرو وأدرِج واحدًا للبدء من أوامره."}}],topics:{simulator:{title:{t:0,b:{t:2,i:[{t:3}],s:"المحاكي"}},body:{t:0,b:{t:2,i:[{t:3}],s:"يشغّل البرنامج على رأس أداة افتراضي: حركات G0/G1، وG90/G91 (مطلق/نسبي)، وM82/M83 (وضع الباثق)، وG92 (تعيين الموضع)، وG28 (التصفير ← نقطة الأصل). ويبلّغ عن المسار، والمربّع المحيط، وإجمالي التنقّل والبثق، وتقديرًا تقريبيًا للوقت من معدّلات التغذية، وجدولًا زمنيًا لكل أمر. ولا يُرسَل أي شيء إلى الطابعة."}}},motion:{title:{t:0,b:{t:2,i:[{t:3}],s:"المسار والوقت"}},body:{t:0,b:{t:2,i:[{t:3}],s:"العرض ثنائي الأبعاد هو مسار XY (يظهر Z ضمن الحدود). يقسّم تقدير الوقت طول كل حركة على معدّل تغذيتها — وهو يتجاهل التسارع، لذا فهو حدّ أدنى تقريبي، وليس زمن الطباعة الدقيق. أمّا الأوامر التي لا يحاكيها المحاكي (مثل M-codes والماكرو عالية المستوى) فتُدرَج كتحذيرات وتُتخطَّى."}}},macros:{title:{t:0,b:{t:2,i:[{t:3}],s:"مكتبة الماكرو"}},body:{t:0,b:{t:2,i:[{t:3}],s:'مجموعة مرجعية من ماكرو Klipper الشائعة مع اسمها، ووظيفتها، وأقسام التهيئة التي تحتاجها. يُدرِج خيار "إدراج" أوامر الماكرو عالية المستوى في المحرّر كنقطة انطلاق — لاحظ أنّ هذه الأوامر تتوسّع أكثر على الطابعة (توسيع Jinja/الماكرو الكامل قادم).'}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"مسرد المصطلحات"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{gcode:{term:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},def:{t:0,b:{t:2,i:[{t:3}],s:"لغة الحركة سطرًا بسطر التي تشغّلها الطابعة (الحركات، ودرجات الحرارة، والمروحة، …)."}}},feedrate:{term:{t:0,b:{t:2,i:[{t:3}],s:"معدّل التغذية (F)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"سرعة الحركة بوحدة mm/min — حيث F1200 تعادل 20 mm/s. يحدّد سرعة تشغيل كل حركة."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"الماكرو"}},def:{t:0,b:{t:2,i:[{t:3}],s:"أمر مسمّى وقابل لإعادة الاستخدام (مثل QUAD_GANTRY_LEVEL) يتوسّع إلى سلسلة من G-code."}}}}},editor:{label:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},simulate:{t:0,b:{t:2,i:[{t:3}],s:"محاكاة"}},simulating:{t:0,b:{t:2,i:[{t:3}],s:"جارٍ المحاكاة…"}},sample:{t:0,b:{t:2,i:[{t:3}],s:"تحميل نموذج"}},clear:{t:0,b:{t:2,i:[{t:3}],s:"مسح"}}},library:{label:{t:0,b:{t:2,i:[{t:3}],s:"ماكرو مدمجة"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"تصفّح الماكرو…"}},insert:{t:0,b:{t:2,i:[{t:3}],s:"إدراج في المحرّر"}},requires:{t:0,b:{t:2,i:[{t:3,v:"يحتاج: "},{t:4,k:"sections"}]}},none:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"المحاكاة"}},moves:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" حركة"}]}},distance:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm تنقّل"}]}},extrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm مبثوق"}]}},time:{t:0,b:{t:2,i:[{t:3,v:"~"},{t:4,k:"s"},{t:3,v:" ث"}]}},bounds:{t:0,b:{t:2,i:[{t:3}],s:"الحدود"}},empty:{t:0,b:{t:2,i:[{t:3}],s:"لا توجد حركات لمحاكاتها."}}},path:{title:{t:0,b:{t:2,i:[{t:3}],s:"مسار رأس الأداة (XY)"}},noPath:{t:0,b:{t:2,i:[{t:3}],s:"شغّل محاكاة لرؤية المسار."}}},timeline:{title:{t:0,b:{t:2,i:[{t:3}],s:"الجدول الزمني"}},line:{t:0,b:{t:2,i:[{t:3}],s:"السطر"}},cmd:{t:0,b:{t:2,i:[{t:3}],s:"الأمر"}},action:{t:0,b:{t:2,i:[{t:3}],s:"الإجراء"}}},warnings:{title:{t:0,b:{t:2,i:[{t:3}],s:"تحذيرات"}}},explain:{title:{t:0,b:{t:2,i:[{t:3}],s:"اشرح هذا الماكرو"}},travel:{t:0,b:{t:2,i:[{t:3,v:"تنقّل سريع إلى X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" بسرعة "},{t:4,k:"f"},{t:3,v:" مم/د"}]}},print:{t:0,b:{t:2,i:[{t:3,v:"حركة طباعة — بثق "},{t:4,k:"e"},{t:3,v:" مم على مسافة "},{t:4,k:"d"},{t:3,v:" مم إلى X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:" بسرعة "},{t:4,k:"f"},{t:3,v:" مم/د"}]}},retract:{t:0,b:{t:2,i:[{t:3,v:"سحب "},{t:4,k:"e"},{t:3,v:" مم"}]}},prime:{t:0,b:{t:2,i:[{t:3,v:"بثق "},{t:4,k:"e"},{t:3,v:" مم في المكان"}]}},noMove:{t:0,b:{t:2,i:[{t:3}],s:"لا حركة"}},absXYZ:{t:0,b:{t:2,i:[{t:3}],s:"التحويل إلى تموضع مطلق (G90)"}},relXYZ:{t:0,b:{t:2,i:[{t:3}],s:"التحويل إلى تموضع نسبي (G91)"}},absE:{t:0,b:{t:2,i:[{t:3}],s:"التحويل إلى بثق مطلق (M82)"}},relE:{t:0,b:{t:2,i:[{t:3}],s:"التحويل إلى بثق نسبي (M83)"}},setPos:{t:0,b:{t:2,i:[{t:3}],s:"تعيين الموضع الحالي (G92)"}},home:{t:0,b:{t:2,i:[{t:3}],s:"تصفير المحاور (G28) ← الأصل"}},abs:{t:0,b:{t:2,i:[{t:3}],s:"مطلق"}},rel:{t:0,b:{t:2,i:[{t:3}],s:"نسبي"}},cum:{t:0,b:{t:2,i:[{t:3,v:"حتى الآن: "},{t:4,k:"d"},{t:3,v:" مم · "},{t:4,k:"e"},{t:3,v:" مم · ~"},{t:4,k:"s"},{t:3,v:" ث"}]}},note:{t:0,b:{t:2,i:[{t:3}],s:"الأسطر ذات التعابير غير المحلولة أو تحكّم Jinja لا تُحاكى وتُحذف هنا."}}},live:{label:{t:0,b:{t:2,i:[{t:3}],s:"من الطابعة"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"اختر أحد ماكروهاتك المثبّتة…"}},hint:{t:0,b:{t:2,i:[{t:3,v:"عُثر على "},{t:4,k:"n"},{t:3,v:" ماكرو في الطابعة — اختر واحدًا لتحميل كوده ومحاكاته."}]}},unreachable:{t:0,b:{t:2,i:[{t:3}],s:"الطابعة غير متاحة — اتصل لتحميل ماكروهاتك المثبّتة."}},params:{t:0,b:{t:2,i:[{t:3}],s:"معاملات الماكرو"}}},limits:{title:{t:0,b:{t:2,i:[{t:3}],s:"خارج الحدود / تجاوز السرعة"}},oob:{t:0,b:{t:2,i:[{t:3,v:"السطر "},{t:4,k:"line"},{t:3,v:": "},{t:4,k:"axis"},{t:3,v:"="},{t:4,k:"value"},{t:3,v:" خارج منطقة البناء ("},{t:4,k:"min"},{t:3,v:"…"},{t:4,k:"max"},{t:3,v:" مم)."}]}},overSpeed:{t:0,b:{t:2,i:[{t:3,v:"السطر "},{t:4,k:"line"},{t:3,v:": "},{t:4,k:"value"},{t:3,v:" مم/ث يتجاوز حدّ الطابعة "},{t:4,k:"limit"},{t:3,v:" مم/ث (سيقيّده Klipper)."}]}},buildArea:{t:0,b:{t:2,i:[{t:3,v:"منطقة البناء "},{t:4,k:"x"},{t:3,v:"×"},{t:4,k:"y"},{t:3,v:" مم"}]}}}}};export{t as default};
